var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 G 스타디움\\n<color=#ffd34c>VIP 라운지</color>\\n예선 최종전 진행 중","JPN":"シャレードGスタジアム\\n<color=#ffd34c>VIPラウンジ</color>\\n予選の最終戦、進行中","ENG":"Charade G Stadium\\n<color=#ffd34c>VIP Lounge</color>\\nFinal match for the qualifiers in progress","TWN":"查雷德G體育場\\n<color=#ffd34c>VIP室</color>\\n預賽最終場進行中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 뭔가 좀 보여 주는군! 그릴 파티!","JPN":"やっと何か見せてくれるんだな！　グリルパーティー！","ENG":"Finally! You're giving us something, Grill Party!","TWN":"終於有點看頭囉！格里爾派提！"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"더 밀어붙여! 너희들에게 오늘 전부 베팅했다고!","JPN":"もっと追い込め！　今日はお前らに全額かけたんだよ！","ENG":"Go on, take them down! I bet everything on you today!","TWN":"繼續保持！我把身家都押在你們身上囉！"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOUNGMAN_NPC_NULL_NULL","text":{"KOREA":"빈민가 변두리에 부지를 확보했어요. 조미료를 쳤으니 곧 재개발 얘기가 나올 겁니다.","JPN":"スラム街のはずれに敷地を確保しておきました。話を盛っておきましたから、すぐ再開発の話が出てくるでしょう。","ENG":"We've acquired land at the outskirts of the slums. I've made some arrangements, and soon the land will be selected for redevelopment.","TWN":"貧民窟周邊的那塊地已經十拿九穩！再加把勁很快就能都更！"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLDWOMAN_NPC_NULL_NULL","text":{"KOREA":"반가운 소식이네요. 입점은 언제 가능할까요?","JPN":"それは嬉しいですね。入店はいつできるのでしょうか？","ENG":"That's great news. When can I enter?","TWN":"很棒的好消息，那什麼時候可以入駐？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어머, 여긴 오랜만에 와도 예전이랑 똑같네?","JPN":"まあ、ここはいつ来ても昔と変わらないわね。","ENG":"My, my. This place never changes, does it?","TWN":"哎呀，這麼久沒來，這裡都沒變呢？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"술도 많고, 사람도 많고, 소란스럽고. 도박장 냄새가 나.","JPN":"酒も多いし、人も多いし、騒がしいし。賭博場の匂いがするの。","ENG":"A lot of booze, a lot of people, and a lot of noise. It smells like a gambling joint in here.","TWN":"酒多，人多，鬧哄哄的，有賭場的味道。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아, 내가 방해했나?","JPN":"あ、私が邪魔したのかしら？","ENG":"Oh, sorry. Did I intrude?","TWN":"喔，我有吵到你們嗎？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하던 일들 보세요. 네.","JPN":"先の続けてね、さあ。","ENG":"Please, go on with whatever business you were up to.","TWN":"你們繼續，不用管我。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"기다렸습니다. 오지만디아스 씨.","JPN":"お待ちしておりました。オジマンディアスさん。","ENG":"I have been waiting for you, Ozymandias.","TWN":"我正等你呢，奧茲曼迪亞斯。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"람다~!","JPN":"ラムダ～！","ENG":"Lamda!","TWN":"蘭達～！"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"스완이 왔다면서? 어디 있어? 사인 좀 받게!","JPN":"スワンが来たんだってね？　どこにいるの？　サインしてもらうわ！","ENG":"I heard that Swan was here! Where is she? I want her autograph!","TWN":"聽說史旺也來啦？她在哪裡呢？我要跟她要簽名！"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"라운지에는 방문하지 않았습니다.","JPN":"ラウンジには訪問していません。","ENG":"She did not visit the lounge.","TWN":"她不在VIP室裡。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"개인실에서 관람하고 있겠죠. 거장들의 연락도 자동 응답기로 받을 정도니까요.","JPN":"個室で観覧しているのでしょう。大物からの連絡も、自動応答にしているくらいですから。","ENG":"She is probably in her private room, watching. She doesn't answer anyone directly, not even a bigwig. She only answers by the answering machine.","TWN":"她應該在私人包廂裡，大人物的聯繫也都轉到自動答錄機。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L21_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"진짜? 아깝다. 사인 받아다 액자에 보관하려고 했는데.","JPN":"本当？　もったいないわね。サインしてもらって、額に入れて保管しようと思ったのに。","ENG":"Really? Such a shame. I wanted to frame her autograph.","TWN":"真的嗎？好可惜，我還想拿到簽名後用相框裱起來呢。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"……잊은 건 아니겠죠. 저는 법적 대응이 필요한 상황에 대응해 주기 위해 온 겁니다.","JPN":"……忘れていないでしょうね。私は法的対応が必要な状況に対応してあげるために来たわけです。","ENG":"...I hope you did not forget why we are here. I am here to advise you on legal issues.","TWN":"……你沒忘記吧？我來這裡是因為有需要採取法律措施的情況。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"잡담을 나누는 시간도 상담에 속해요.","JPN":"雑談をする時間も相談に該当します。","ENG":"All this small talk is considered part of the consultation and will be charged.","TWN":"閒聊的時間諮詢費照算。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 정도는 좀 눈 감아 줘. 조니 앤 멜로니를 먹여 살리는 사람이 난데.","JPN":"そのくらいは大目に見てほしいわ。ジョニー＆メロニーを養ってるのは私よ。","ENG":"Come on, cut me some slack. I'm the one keeping Jonie & Melonie in business.","TWN":"給點耐心嘛，畢竟養活強尼＆梅蘭妮的人可是我呢。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이 도시의 전통과 관습들이 20년만에 생겼다고 오판하지 않길 바랍니다.","JPN":"この街の伝統と慣習が、たった20年でできたと誤断しないでください。","ENG":"Please do not assume that the traditions and customs of this city were created only 20 years ago.","TWN":"這座城市的傳統和習俗已經行之有年。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신의 스폰서들을 제외하고도 우리를 찾는 곳은 많아요.","JPN":"あなたのスポンサーを除いても、私たちを探しているところは多いです。","ENG":"Even without your sponsors, we have many other clients.","TWN":"就算沒有你的贊助，還有很多其他地方需要我們。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"까칠하네. 그런 면이 마음에 들긴 하지만.","JPN":"冷たいわね。そんなところが気に入ってるけど。","ENG":"Cheeky. I like that, though.","TWN":"真不留情面，不過我喜歡。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"경기는 어때? 하이라이트 좀 나왔어?","JPN":"試合はどう？　ちょっとハイライトとか出たのかしら。","ENG":"How's the match? Any highlights?","TWN":"比賽怎麼樣？已經到精彩部分嗎？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"야간전으로 들어가자마자 전세가 역전되더군요.","JPN":"夜間戦に突入して、すぐ戦況が逆転しました。","ENG":"As soon as the lights went off, the tide of war changed.","TWN":"一進入夜戰模式，局勢就開始逆轉。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"미리 짜 둔 시나리오대로 굴러가는 거지.","JPN":"シナリオどおりね。","ENG":"It's all according to the script.","TWN":"那就是在按照事先編好的劇情在發展囉？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 늘 말했잖아. 우리 애들 이 방면에서 아주 전문가라니까?","JPN":"いつも言ってるじゃない。うちの子たちは、この方面の専門家なの。","ENG":"I told you many times. Our boys are experts at stuff like this!","TWN":"我就說嘛，我的人在這方面是非常專業的。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"디펜더는 도망치다 4층 높이에서 잘못 떨어지는 바람에 복합골절로 리타이어.","JPN":"ディフェンダーは逃げる途中に4階の高さから落ちて、複雑骨折でリタイア。","ENG":"The defender falls from four stories high after an intense chase.","TWN":"護衛在逃跑途中不慎從4樓摔落，發生多處骨折並因此棄權。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"레인저는 격투 중에 모서리에 부딪쳐서 의식 불명 상태로 입원.","JPN":"レンジャーは激闘中に角にぶつかって、意識不明の状態で入院。","ENG":"The ranger bangs her head into a corner amidst combat, going unconscious.","TWN":"突擊隊員在戰鬥過程中頭部不小心磕到棱角上，昏迷住院。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"스나이퍼는 카운터라…. 뭐, 가족도 있다니까 적당히 협박해서 겁만 주라고 했지.","JPN":"スナイパーはカウンターだから……まあ、家族もいるらしいし、適当に脅しとけって。","ENG":"The sniper's a Counter... Well, I told them to go easy on her, seeing that she has a family and all.","TWN":"狙擊手是制裁者…畢竟她有家人，就稍微威脅一下，嚇嚇她就好。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어때, 내 배려심? 이게 바로 스포츠맨쉽 아냐?","JPN":"どう？　私の気遣い。これこそスポーツマンシップじゃないかしら。","ENG":"What do you think? Isn't this true sportsmanship?","TWN":"怎麼樣，我貼心吧？這不就是所謂的運動家精神嗎？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"다른 사람 자존심 챙겨 주려고 불필요한 법적 분쟁의 소지를 자초할 필요가 있나요?","JPN":"他人のプライドに気を配って、不要な法的紛争の素地を招く必要があるのですか？","ENG":"Was it really necessary to start a legal dispute just to boost someone else's ego?","TWN":"你有必要為了顧及他人的自尊心，而引來不必要的法律糾紛嗎？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"불필요하다니. 다 자존심 세우자고 돈 버는 건데.","JPN":"不要って。全部プライドのためにお金を稼いでるのに。","ENG":"Unnecessary? Honey, everything is about ego.","TWN":"怎麼會沒必要？沒有錢哪來的自尊心。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"실탄은 허용하지 않았겠죠? 와일러의 재판 결과에 영향이 갈 수 있어요.","JPN":"実弾は許可してないですよね。ワイラーの裁判結果に影響を及ぼす可能性があります。","ENG":"I hope you didn't allow live ammunition. It might affect Wyler's trial.","TWN":"你沒讓他們使用實彈吧？這可能會影響到瓦勒的審判結果。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"당연히 안 쓰지. 내가 바보도 아니고.","JPN":"もちろん使わないわ。愚か者ではないのだから。","ENG":"Of course not. I'm not an idiot.","TWN":"當然沒有，我又不是傻子。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>펠리세트 선수! 방패를 놓치고 나동그라집니다!</color>","JPN":"<color=#ffd34c>フェリセット選手！　盾を落として転んでしまいました！</color>","ENG":"<color=#ffd34c>Félicette! She drops her shield and falls to the ground!</color>","TWN":"<color=#ffd34c>費莉塞特選手！沒抓住盾牌摔個狗吃屎！</color>"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아, 우는 건가요? 이제 와서 어린아이인 척 하려고 해도 늦었죠!</color>","JPN":"<color=#ffd34c>ああ、泣いてるんでしょうか？　今更子どものふりをしようとしても遅いです！</color>","ENG":"<color=#ffd34c>Oh, are those tears in her eyes? It's too late to act like an innocent child!</color>","TWN":"<color=#ffd34c>喔？她是在哭嗎？現在才想裝作小孩博取同情會不會太遲！</color>"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……응? 쟤 뭐야?","JPN":"……うん？　あの子、何？","ENG":"...Huh? Who's that?","TWN":"……嗯？她是誰？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"카나리아 스쿼드의 리더입니다.","JPN":"カナリア・スクワッドのリーダーです。","ENG":"She's the leader of Canary Squad.","TWN":"那是金絲雀小隊的隊長。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"자기가 불구로 만들 사람 얼굴은 기억해 두세요. 법정에서 불성실한 태도로 해석될 수 있으니까요.","JPN":"自分が障害者にする人の顔は覚えておいてください。法廷で不真面目な態度と解釈される可能性がありますから。","ENG":"At least try to remember the faces of the people you are going to harm. You don't want to be seen as insincere in court.","TWN":"你要把人家弄殘廢起碼也記住她的臉，否則在法庭上法官會認為你態度輕浮的。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"호오…? 저 애가?","JPN":"へえ……？　あの子が？","ENG":"Aha... She's the leader?","TWN":"喔呵……？那孩子是？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"곤란하네. 이러면 얘기가 다르잖아.","JPN":"困ったわね。こうなると話が違うわ。","ENG":"That won't do. This isn't right.","TWN":"真傷腦筋，這樣情況完全不同囉。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쟤는 병아리가 아니라 예술가거든.","JPN":"あの子、ヒヨコじゃなくて芸術家なの。","ENG":"What you're looking at is not a mere chick, but an artist.","TWN":"她不是什麼菜鳥，她是藝術家。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그리고 예술가는 원래 모두 미치광이들이야. 나처럼.","JPN":"そして芸術家は元々みんな狂人よ。私のように。","ENG":"And all artists, like myself, are lunatics.","TWN":"但所謂的藝術家都是瘋子，就像我一樣。"},"stage":{"bg":"CLUB1","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};